1 | // ═══════════════════════════════════════════════
2 | //  HealthAI — Express Backend Proxy
3 | //  Proxies IBM IAM token + WatsonX API calls
4 | //  so the browser never touches IBM directly.
5 | // ═══════════════════════════════════════════════
6 | 
7 | const express = require('express');
8 | const path    = require('path');
9 | 
10 | const app  = express();
11 | const PORT = process.env.PORT || 3000;
12 | 
13 | // ── IBM WatsonX config (server-side only) ──
14 | const IBM_CONFIG = {
15 |     projectId: 'a0a5cc1f-6385-4952-be11-f9c19c29b36e',
16 |     apiKey:    's2tJtVXy9V9H8iMjsMo_aGtMyIGMElrR-IYzlSecKcyP',
17 |     endpoint:  'https://us-south.ml.cloud.ibm.com',
18 |     modelId:   'ibm/granite-3-8b-instruct'
19 | };
20 | 
21 | // ── Token cache ──
22 | let cachedToken  = null;
23 | let tokenExpiry  = 0;
24 | 
25 | app.use(express.json());
26 | 
27 | // Serve static frontend files
28 | app.use(express.static(path.join(__dirname)));
29 | 
30 | // ── POST /api/chat  ──────────────────────────
31 | // Body: { prompt: string, parameters: object }
32 | app.post('/api/chat', async (req, res) => {
33 |     try {
34 |         const { prompt, parameters } = req.body;
35 |         if (!prompt) return res.status(400).json({ error: 'prompt is required' });
36 | 
37 |         const token = await getAccessToken();
38 | 
39 |         const ibmRes = await fetch(
40 |             `${IBM_CONFIG.endpoint}/ml/v1/text/generation?version=2023-05-29`,
41 |             {
42 |                 method:  'POST',
43 |                 headers: {
44 |                     'Content-Type':  'application/json',
45 |                     'Authorization': `Bearer ${token}`,
46 |                     'Accept':        'application/json'
47 |                 },
48 |                 body: JSON.stringify({
49 |                     model_id:   IBM_CONFIG.modelId,
50 |                     project_id: IBM_CONFIG.projectId,
51 |                     input:      prompt,
52 |                     parameters: parameters || {
53 |                         decoding_method:    'greedy',
54 |                         max_new_tokens:     1024,
55 |                         min_new_tokens:     10,
56 |                         stop_sequences:     ['<|user|>', '<|system|>'],
57 |                         repetition_penalty: 1.05
58 |                     }
59 |                 })
60 |             }
61 |         );
62 | 
63 |         if (!ibmRes.ok) {
64 |             const errText = await ibmRes.text();
65 |             console.error('WatsonX error:', ibmRes.status, errText);
66 |             return res.status(ibmRes.status).json({ error: errText });
67 |         }
68 | 
69 |         const data = await ibmRes.json();
70 |         res.json(data);
71 | 
72 |     } catch (err) {
73 |         console.error('Proxy /api/chat error:', err.message);
74 |         res.status(500).json({ error: err.message });
75 |     }
76 | });
77 | 
78 | // ── Internal: fetch + cache IAM token ────────
79 | async function getAccessToken() {
80 |     const now = Date.now();
81 |     if (cachedToken && now < tokenExpiry - 60_000) return cachedToken;
82 | 
83 |     const iamRes = await fetch('https://iam.cloud.ibm.com/identity/token', {
84 |         method:  'POST',
85 |         headers: {
86 |             'Content-Type': 'application/x-www-form-urlencoded',
87 |             'Accept':       'application/json'
88 |         },
89 |         body: `grant_type=urn:ibm:params:oauth:grant-type:apikey&apikey=${IBM_CONFIG.apiKey}`
90 |     });
91 | 
92 |     if (!iamRes.ok) {
93 |         const txt = await iamRes.text();
94 |         throw new Error(`IAM token error ${iamRes.status}: ${txt}`);
95 |     }
96 | 
97 |     const data    = await iamRes.json();
98 |     cachedToken   = data.access_token;
99 |     tokenExpiry   = now + (data.expires_in * 1000);
100 |     return cachedToken;
101 | }
102 | 
103 | // ── Catch-all: serve index.html for SPA ──────
104 | app.get('*', (req, res) => {
105 |     res.sendFile(path.join(__dirname, 'index.html'));
106 | });
107 | 
108 | app.listen(PORT, () => {
109 |     console.log(`\n  HealthAI server running at http://localhost:${PORT}\n`);
110 | });
111 |

